     1→import { PrismaClient } from "../prisma/generated/client/index.js";
     2→import { PrismaBetterSqlite3 } from "@prisma/adapter-better-sqlite3";
     3→import { mkdirSync } from "fs";
     4→import { resolve, dirname } from "path";
     5→
     6→// ─── Shared state types ───────────────────────────────────────────────────────
     7→
     8→export interface SessionRecord {
     9→  sessionId: string;
    10→  startedAt: string;  // ISO string
    11→  updatedAt: string;  // ISO string
    12→  cwd: string;
    13→  repoRoot?: string;
    14→  repoName?: string;
    15→  parentSessionId?: string;
    16→  gitUserName?: string;
    17→  gitUserEmail?: string;
    18→  prompt?: string;
    19→  summary?: string;
    20→  keywords?: string[];
    21→}
    22→
    23→export interface PendingToolUseRecord {
    24→  tool_use_id: string;
    25→  tool_name: string;
    26→  tool_input?: unknown;
    27→  startedAt: string; // pre-formatted display string from fmt()
    28→}
    29→
    30→export interface State {
    31→  sessions: Record<string, SessionRecord>;
    32→  // Maps agent_id → parent session_id so we can link child SessionStart events
    33→  agentParents: Record<string, string>;
    34→  // Maps tool_use_id → stashed PreToolUse data, cleared on PostToolUse
    35→  pendingToolUses: Record<string, PendingToolUseRecord>;
    36→}
    37→
    38→// ─── Singleton DB cache ───────────────────────────────────────────────────────
    39→
    40→const dbCache = new Map<string, PrismaClient>();
    41→
    42→/**
    43→ * Open (or return cached) a PrismaClient backed by a better-sqlite3 file at `dbPath`.
    44→ * Runs PRAGMA journal_mode=WAL for safe concurrent writes.
    45→ */
    46→export async function getDb(dbPath: string): Promise<PrismaClient> {
    47→  const abs = resolve(dbPath);
    48→  const cached = dbCache.get(abs);
    49→  if (cached) return cached;
    50→
    51→  mkdirSync(dirname(abs), { recursive: true });
    52→
    53→  const adapter = new PrismaBetterSqlite3({ url: `file:${abs}` });
    54→  const db = new PrismaClient({ adapter } as ConstructorParameters<typeof PrismaClient>[0]);
    55→
    56→  try {
    57→    await db.$queryRawUnsafe("PRAGMA journal_mode=WAL");
    58→  } catch {
    59→    // Non-fatal — WAL mode is a performance hint
    60→  }
    61→
    62→  dbCache.set(abs, db);
    63→  return db;
    64→}
    65→
    66→// ─── State read/write ─────────────────────────────────────────────────────────
    67→
    68→/** Read all session state tables and assemble an in-memory State object. */
    69→export async function readStateFromDb(db: PrismaClient): Promise<State> {
    70→  const [sessions, agentParents, pendingToolUses] = await Promise.all([
    71→    db.session.findMany(),
    72→    db.agentParent.findMany(),
    73→    db.pendingToolUse.findMany(),
    74→  ]);
    75→
    76→  const sessionMap: Record<string, SessionRecord> = {};
    77→  for (const s of sessions) {
    78→    sessionMap[s.sessionId] = {
    79→      sessionId: s.sessionId,
    80→      startedAt: s.startedAt instanceof Date ? s.startedAt.toISOString() : String(s.startedAt),
    81→      updatedAt: s.updatedAt instanceof Date ? s.updatedAt.toISOString() : String(s.updatedAt),
    82→      cwd: s.cwd,
    83→      repoRoot: s.repoRoot ?? undefined,
    84→      repoName: s.repoName ?? undefined,
    85→      parentSessionId: s.parentSessionId ?? undefined,
    86→      gitUserName: s.gitUserName ?? undefined,
    87→      gitUserEmail: s.gitUserEmail ?? undefined,
    88→      prompt: s.prompt ?? undefined,
    89→      summary: s.summary ?? undefined,
    90→      keywords: s.keywords ? (JSON.parse(s.keywords) as string[]) : undefined,
    91→    };
    92→  }
    93→
    94→  const agentParentMap: Record<string, string> = {};
    95→  for (const ap of agentParents) {
    96→    agentParentMap[ap.agentId] = ap.parentSessionId;
    97→  }
    98→
    99→  const pendingMap: Record<string, PendingToolUseRecord> = {};
   100→  for (const p of pendingToolUses) {
   101→    pendingMap[p.toolUseId] = {
   102→      tool_use_id: p.toolUseId,
   103→      tool_name: p.toolName,
   104→      tool_input: p.toolInput ? (JSON.parse(p.toolInput) as unknown) : undefined,
   105→      startedAt: p.startedAt,
   106→    };
   107→  }
   108→
   109→  return { sessions: sessionMap, agentParents: agentParentMap, pendingToolUses: pendingMap };
   110→}
   111→
   112→/** Persist in-memory State to the database. Uses upsert for sessions; replaces agent/pending tables. */
   113→export async function writeStateToDb(db: PrismaClient, state: State): Promise<void> {
   114→  // Upsert each session
   115→  await Promise.all(
   116→    Object.values(state.sessions).map((s) =>
   117→      db.session.upsert({
   118→        where: { sessionId: s.sessionId },
   119→        create: {
   120→          sessionId: s.sessionId,
   121→          startedAt: new Date(s.startedAt),
   122→          updatedAt: new Date(s.updatedAt),
   123→          cwd: s.cwd,
   124→          repoRoot: s.repoRoot ?? null,
   125→          repoName: s.repoName ?? null,
   126→          parentSessionId: s.parentSessionId ?? null,
   127→          gitUserName: s.gitUserName ?? null,
   128→          gitUserEmail: s.gitUserEmail ?? null,
   129→          prompt: s.prompt ?? null,
   130→          summary: s.summary ?? null,
   131→          keywords: s.keywords ? JSON.stringify(s.keywords) : null,
   132→        },
   133→        update: {
   134→          updatedAt: new Date(s.updatedAt),
   135→          cwd: s.cwd,
   136→          repoRoot: s.repoRoot ?? null,
   137→          repoName: s.repoName ?? null,
   138→          parentSessionId: s.parentSessionId ?? null,
   139→          gitUserName: s.gitUserName ?? null,
   140→          gitUserEmail: s.gitUserEmail ?? null,
   141→          prompt: s.prompt ?? null,
   142→          summary: s.summary ?? null,
   143→          keywords: s.keywords ? JSON.stringify(s.keywords) : null,
   144→        },
   145→      })
   146→    )
   147→  );
   148→
   149→  // Replace agentParents wholesale
   150→  await db.agentParent.deleteMany();
   151→  const agentEntries = Object.entries(state.agentParents);
   152→  if (agentEntries.length > 0) {
   153→    await db.agentParent.createMany({
   154→      data: agentEntries.map(([agentId, parentSessionId]) => ({ agentId, parentSessionId })),
   155→    });
   156→  }
   157→
   158→  // Replace pendingToolUses wholesale
   159→  await db.pendingToolUse.deleteMany();
   160→  const pendingEntries = Object.values(state.pendingToolUses);
   161→  if (pendingEntries.length > 0) {
   162→    await db.pendingToolUse.createMany({
   163→      data: pendingEntries.map((p) => ({
   164→        toolUseId: p.tool_use_id,
   165→        toolName: p.tool_name,
   166→        toolInput: p.tool_input !== undefined ? JSON.stringify(p.tool_input) : null,
   167→        startedAt: p.startedAt,
   168→      })),
   169→    });
   170→  }
   171→}
