   537→// ─── V2 full-tree indexer ─────────────────────────────────────────────────────
   538→
   539→export async function indexAllCheckpointsV2(
   540→  db: PrismaClient,
   541→  rootDir: string,
   542→  onProgress?: (checkpointId: string) => void,
   543→): Promise<{ checkpoints: number }> {
   544→  let totalCheckpoints = 0;
   545→
   546→  const shards = readdirSync(rootDir)
   547→    .filter((e) => /^[0-9a-f]{2}$/i.test(e) && statSync(join(rootDir, e)).isDirectory());
   548→
   549→  for (const shard of shards) {
   550→    const shardPath = join(rootDir, shard);
   551→    const ids = readdirSync(shardPath)
   552→      .filter((e) => /^[0-9a-f]{10}$/i.test(e) && statSync(join(shardPath, e)).isDirectory());
   553→
   554→    for (const rest of ids) {
   555→      const checkpointId  = shard + rest;
   556→      const checkpointDir = join(shardPath, rest);
   557→      try {
   558→        await indexCheckpointV2(db, checkpointDir, checkpointId);
   559→        totalCheckpoints++;
   560→        onProgress?.(checkpointId);
   561→      } catch (err) {
   562→        process.stderr.write(`indexer-v2: skipping ${checkpointId}: ${err}\n`);
   563→      }
   564→    }
   565→  }
   566→
   567→  return { checkpoints: totalCheckpoints };
   568→}
