   570→// ─── Full-tree indexer (V1 / old schema) ─────────────────────────────────────
   571→
   572→/**
   573→ * Walk a checkpoints root directory and index every checkpoint found.
   574→ *
   575→ * The root must have the shard structure:
   576→ *   <root>/<2-hex-chars>/<10-hex-chars>/
   577→ *
   578→ * @param onProgress  Optional callback called after each checkpoint.
   579→ */
   580→export async function indexAllCheckpoints(
   581→  db: PrismaClient,
   582→  rootDir: string,
   583→  onProgress?: (checkpointId: string, newMessages: number) => void,
   584→): Promise<{ checkpoints: number; newMessages: number }> {
   585→  let totalCheckpoints = 0;
   586→  let totalNew = 0;
   587→
   588→  const shards = readdirSync(rootDir)
   589→    .filter((e) => /^[0-9a-f]{2}$/i.test(e) && statSync(join(rootDir, e)).isDirectory());
   590→
   591→  for (const shard of shards) {
   592→    const shardPath = join(rootDir, shard);
   593→    const ids = readdirSync(shardPath)
   594→      .filter((e) => /^[0-9a-f]{10}$/i.test(e) && statSync(join(shardPath, e)).isDirectory());
   595→
   596→    for (const rest of ids) {
   597→      const checkpointId = shard + rest;
   598→      const checkpointDir = join(shardPath, rest);
   599→      try {
   600→        const n = await indexCheckpoint(db, checkpointDir, checkpointId);
   601→        totalNew += n;
   602→        totalCheckpoints++;
   603→        onProgress?.(checkpointId, n);
   604→      } catch (err) {
   605→        process.stderr.write(`indexer: skipping ${checkpointId}: ${err}\n`);
   606→      }
   607→    }
   608→  }
   609→
   610→  return { checkpoints: totalCheckpoints, newMessages: totalNew };
   611→}
