   140→export async function startServer(dbPath: string, port: number, repoDir?: string): Promise<void> {
   141→  // Strip CLAUDECODE so spawned sessions are not blocked by nested-session detection
   142→  delete process.env.CLAUDECODE;
   143→
   144→  const db = await getDb(dbPath);
   145→
   146→  const app = express();
   147→  app.use(cors());
   148→  app.use(express.json());
   149→
   150→  // GET /api/sessions
   151→  app.get("/api/sessions", async (_req, res) => {
   152→    try {
   153→      const sessions = await db.session.findMany({
   154→        orderBy: { updatedAt: "desc" },
   155→      });
   156→      const sessionIds = sessions.map((s) => s.sessionId);
   157→
   158→      // Fetch latest branch and intent per session from CheckpointSessionMetadata
   159→      const sessionMetas = await db.checkpointSessionMetadata.findMany({
   160→        where: { sessionId: { in: sessionIds } },
   161→        select: { sessionId: true, branch: true, createdAt: true, summary: { select: { intent: true } } },
   162→        orderBy: { createdAt: "desc" },
   163→      });
   164→      const branchMap = new Map<string, string | null>();
   165→      const intentMap = new Map<string, string | null>();
   166→      for (const m of sessionMetas) {
   167→        if (!branchMap.has(m.sessionId)) branchMap.set(m.sessionId, m.branch);
   168→        if (!intentMap.has(m.sessionId)) intentMap.set(m.sessionId, m.summary?.intent ?? null);
   169→      }
   170→
   171→      // Build parent → children map in memory
   172→      const childMap = new Map<string, string[]>();
   173→      for (const s of sessions) {
   174→        if (s.parentSessionId) {
   175→          const arr = childMap.get(s.parentSessionId) ?? [];
   176→          arr.push(s.sessionId);
   177→          childMap.set(s.parentSessionId, arr);
   178→        }
   179→      }
   180→      res.json(sessions.map((s) => mapSession(s, childMap.get(s.sessionId) ?? [], branchMap.get(s.sessionId) ?? null, intentMap.get(s.sessionId) ?? null)));
   181→    } catch (err) {
   182→      res.status(500).json({ error: String(err) });
   183→    }
   184→  });
   185→
   186→  // GET /api/sessions/:id
   187→  app.get("/api/sessions/:id", async (req, res) => {
