   198→          orderBy: { createdAt: "desc" },
   199→        }),
   200→      ]);
   201→      if (!session) {
   202→        res.status(404).json({ error: "Session not found" });
   203→        return;
   204→      }
   205→      res.json(mapSession(session, children.map((c) => c.sessionId), latestMeta?.branch ?? null, latestMeta?.summary?.intent ?? null));
   206→    } catch (err) {
   207→      res.status(500).json({ error: String(err) });
