   563→    const id = parseInt(req.params.id, 10);
   564→    const { status, subSessionId } = req.body as { status?: string; subSessionId?: string };
   565→    const allowed = ["open", "in_progress", "complete", "na"];
   566→    if (status !== undefined && !allowed.includes(status)) {
   567→      res.status(400).json({ error: "status must be open, in_progress, or complete" });
   568→      return;
   569→    }
   570→    try {
   571→      const updated = await db.openItem.update({
