   573→        data: {
   574→          ...(status !== undefined ? { status } : {}),
   575→          ...(subSessionId !== undefined ? { subSessionId } : {}),
   576→        },
   577→      });
   578→      res.json({ id: updated.id, status: updated.status, subSessionId: updated.subSessionId });
