   584→  // POST /api/sessions/spawn
   585→  app.post("/api/sessions/spawn", async (req, res) => {
   586→    const { prompt, cwd, openItemIds } = req.body as { prompt?: string; cwd?: string; openItemIds?: number[] };
   587→    if (!prompt || typeof prompt !== "string") {
   588→      res.status(400).json({ error: "prompt is required" });
   589→      return;
   590→    }
   591→    try {
   592→      const safeCwd = (cwd ?? process.env.HOME ?? "/tmp").replace(/'/g, "'\\''");
   593→      const safePrompt = prompt.replace(/'/g, "'\\''").replace(/\\/g, "\\\\").replace(/"/g, '\\"');
   594→      // Pass open item IDs so the SessionStart hook can link the new session back
   595→      const envPrefix = openItemIds?.length
   596→        ? `GOSSAMER_SPAWN_OPEN_ITEMS='${openItemIds.join(",")}' `
   597→        : "";
   598→      // Use AppleScript to open a new Terminal window running claude interactively
   599→      const script = [
   600→        `tell application "Terminal"`,
   601→        `  activate`,
   602→        `  do script "cd '${safeCwd}' && ${envPrefix}claude '${safePrompt}'"`,
   603→        `end tell`,
   604→      ].join("\n");
   605→      execSync(`osascript -e '${script.replace(/'/g, "'\\''")}'`);
   606→      // Mark selected open items as in_progress
   607→      if (openItemIds?.length) {
   608→        await db.openItem.updateMany({
   609→          where: { id: { in: openItemIds } },
   610→          data: { status: "in_progress" },
   611→        });
   612→      }
   613→      res.json({ started: true });
   614→    } catch (err) {
   615→      res.status(500).json({ error: String(err) });
   616→    }
   617→  });
