   619→  // Create HTTP server and attach WebSocket server (shared port)
   620→  const httpServer = createServer(app);
   621→  const wss = new WebSocketServer({ server: httpServer });
   622→
   623→  // WebSocket change detection — poll every 2s, broadcast on new events or checkpoints
   624→  let lastMaxEventId: number | null = null;
   625→  let lastMaxCheckpointId: number | null = null;
   626→  const broadcast = () => {
   627→    const message = JSON.stringify({ type: "sessions_updated" });
   628→    for (const client of wss.clients) {
   629→      if (client.readyState === WebSocket.OPEN) {
   630→        client.send(message);
   631→      }
   632→    }
   633→  };
   634→  const poller = setInterval(async () => {
   635→    try {
   636→      const [latestEvent, latestCheckpoint] = await Promise.all([
   637→        db.event.findFirst({ orderBy: { id: "desc" }, select: { id: true } }),
   638→        db.checkpointMetadata.findFirst({ orderBy: { id: "desc" }, select: { id: true } }),
   639→      ]);
   640→      const currentEventId = latestEvent?.id ?? null;
   641→      const currentCheckpointId = latestCheckpoint?.id ?? null;
   642→      if (currentEventId !== lastMaxEventId || currentCheckpointId !== lastMaxCheckpointId) {
   643→        lastMaxEventId = currentEventId;
   644→        lastMaxCheckpointId = currentCheckpointId;
   645→        broadcast();
   646→      }
   647→    } catch {
   648→      // Non-fatal polling error — keep running
   649→    }
   650→  }, 2000);
   651→
   652→  // ── Checkpoint auto-indexer ───────────────────────────────────────────────
   653→
   654→  const WORKTREE_PATH = "/tmp/gossamer-checkpoints";
   655→  const CHECKPOINT_BRANCH = "entire/checkpoints/v1";
   656→  let checkpointPoller: ReturnType<typeof setInterval> | null = null;
   657→
   658→  if (repoDir) {
   659→    // Ensure worktree exists (reuse across restarts)
   660→    if (!existsSync(WORKTREE_PATH)) {
   661→      try {
   662→        // Prune stale worktree registration first, then re-add
   663→        execSync(`git -C ${JSON.stringify(repoDir)} worktree prune`, { stdio: "pipe" });
   664→        execSync(
   665→          `git -C ${JSON.stringify(repoDir)} worktree add ${JSON.stringify(WORKTREE_PATH)} ${CHECKPOINT_BRANCH}`,
   666→          { stdio: "pipe" },
   667→        );
   668→        process.stderr.write(`checkpoint indexer: worktree created at ${WORKTREE_PATH}\n`);
   669→      } catch (err) {
   670→        process.stderr.write(`checkpoint indexer: failed to create worktree — ${err}\n`);
   671→      }
   672→    }
   673→
   674→    const runIndex = async () => {
   675→      if (!existsSync(WORKTREE_PATH)) return;
   676→      try {
   677→        // Pull latest commits into the worktree working tree
   678→        execSync(`git -C ${JSON.stringify(WORKTREE_PATH)} reset --hard HEAD`, { stdio: "pipe" });
   679→      } catch { /* non-fatal */ }
   680→      try {
   681→        const { newMessages } = await indexAllCheckpoints(db, WORKTREE_PATH);
   682→        if (newMessages > 0) {
   683→          process.stderr.write(`checkpoint indexer: +${newMessages} new messages\n`);
   684→          broadcast();
   685→        }
   686→      } catch { /* non-fatal */ }
   687→      try {
   688→        const { checkpoints } = await indexAllCheckpointsV2(db, WORKTREE_PATH);
   689→        if (checkpoints > 0) {
   690→          process.stderr.write(`checkpoint indexer v2: indexed ${checkpoints} checkpoints\n`);
   691→          broadcast();
   692→        }
   693→      } catch { /* non-fatal */ }
   694→    };
   695→
   696→    void runIndex();
   697→    checkpointPoller = setInterval(runIndex, 30_000);
   698→    process.stderr.write(`checkpoint indexer: polling every 30s (worktree: ${WORKTREE_PATH})\n`);
   699→  }
   700→
   701→  // Graceful shutdown
   702→  const shutdown = () => {
   703→    clearInterval(poller);
   704→    if (checkpointPoller) clearInterval(checkpointPoller);
   705→    httpServer.close();
   706→    process.exit(0);
   707→  };
   708→  process.on("SIGINT", shutdown);
   709→  process.on("SIGTERM", shutdown);
   710→
   711→  await new Promise<void>((resolve) => {
   712→    httpServer.listen(port, () => {
   713→      process.stderr.write(`claude-hook-handler serve: listening on http://localhost:${port}\n`);
   714→      resolve();
   715→    });
   716→  });
   717→}
